import{_ as e,o as a,c as o,a2 as r}from"./chunks/framework.e-meDy3u.js";const h=JSON.parse('{"title":"Q6 · 方案里哪些真需要 Agent，哪些规则脚本就够？","description":"","frontmatter":{},"headers":[],"relativePath":"q6.md","filePath":"q6.md"}'),n={name:"q6.md"};function l(d,t,s,u,i,p){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="q6-·-方案里哪些真需要-agent-哪些规则脚本就够" tabindex="-1">Q6 · 方案里哪些真需要 Agent，哪些规则脚本就够？ <a class="header-anchor" href="#q6-·-方案里哪些真需要-agent-哪些规则脚本就够" aria-label="Permalink to &quot;Q6 · 方案里哪些真需要 Agent，哪些规则脚本就够？&quot;">​</a></h1><p class="hqq-lede">会用 Agent 不难，知道什么时候不该用才值钱。克制是判断力，不是保守。</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p><strong>默认脚本，Agent 是例外。</strong> 绝大多数活儿，规则和脚本就够了；Agent 只留给&quot;输入没结构、规则写不出来、必须靠语义判断&quot;的少数地方。</p><hr><h2 id="一条铁律" tabindex="-1">一条铁律 <a class="header-anchor" href="#一条铁律" aria-label="Permalink to &quot;一条铁律&quot;">​</a></h2><blockquote><p><strong>这件事的逻辑，我能不能用规则明确写出来？</strong></p><ul><li>能写出来 → 脚本。确定、便宜、不会错、出了问题一眼能定位。</li><li>写不出来，输入是人话/图片/杂乱信息 → 才上 Agent。</li></ul></blockquote><p>为什么要卡这么死？Agent 有三个脚本没有的毛病：会错（幻觉）、贵（每次调用烧钱）、难查（错了不好定位）。一件脚本能干的事，你上了 Agent，等于花更多钱、买更多不确定性，还更难维护。这不是先进，是浪费。</p><hr><h2 id="规则脚本就够的-方案里的绝大多数" tabindex="-1">规则脚本就够的（方案里的绝大多数） <a class="header-anchor" href="#规则脚本就够的-方案里的绝大多数" aria-label="Permalink to &quot;规则脚本就够的（方案里的绝大多数）&quot;">​</a></h2><p>这些活儿输入有结构、逻辑能穷举，碰它们用 Agent 就是浪费：</p><table tabindex="0"><thead><tr><th>场景</th><th>为什么脚本够</th></tr></thead><tbody><tr><td>字段映射（千川不同报表里&quot;消耗&quot;和&quot;花费&quot;、&quot;成交&quot;和&quot;转化&quot;对齐）</td><td>映射关系固定，一张表定义一次，脚本机械套用</td></tr><tr><td>去重、入库、增删改查、实时更新</td><td>数据库基本功，要的是&quot;永远不出错&quot;，不是&quot;聪明&quot;</td></tr><tr><td>实验编号生成、命名合规校验</td><td>规则可穷举，脚本又快又稳</td></tr><tr><td>Excel 清洗回写（见 Q4）</td><td>字段清洗是确定逻辑</td></tr><tr><td>异常报警（CTR 高但 3 秒留存低）</td><td>阈值判断，规则就能触发</td></tr></tbody></table><p>方案的骨架这一整块恰恰<strong>不该</strong>碰 Agent——这些地方要的是&quot;永远不出错&quot;，不是聪明。</p><hr><h2 id="真需要-agent-的-少数-但价值高" tabindex="-1">真需要 Agent 的（少数，但价值高） <a class="header-anchor" href="#真需要-agent-的-少数-但价值高" aria-label="Permalink to &quot;真需要 Agent 的（少数，但价值高）&quot;">​</a></h2><p>这些地方输入非结构化，规则覆盖不全，必须靠语义理解：</p><p><strong>客服原话 / 竞品评论聚类</strong>：一堆散乱的用户说法，要归出&quot;购买理由是什么、质疑点在哪、差评苗头是什么&quot;。这没法用规则写，得靠模型读懂语义再归类。</p><p><strong>素材候选生成</strong>：结合 SKU 事实、平台语气、人群场景、合规限制，生成封面/钩子/详情页候选。规则写不出一条好文案。（这正是技术面那个原型干的活。）</p><p><strong>复盘归因草稿</strong>：把曝光、点击、3 秒留存、成交、评论一起摆上来，写出&quot;这条大概率是封面承诺和开头不一致，还是承接页价格问题&quot;。多因素、要解释、要下判断，规则只能报警，做不了归因。</p><p><strong>规则要区分清楚</strong>：异常检测本身是脚本（阈值报警）；解释这个异常<strong>为什么</strong>发生，才是 Agent。报警和归因，一个脚本一个 Agent，别混。</p><hr><h2 id="我自己否掉的那个-聪明想法" tabindex="-1">我自己否掉的那个&quot;聪明想法&quot; <a class="header-anchor" href="#我自己否掉的那个-聪明想法" aria-label="Permalink to &quot;我自己否掉的那个&quot;聪明想法&quot;&quot;">​</a></h2><p>我一度设计过一套方案：把员工填报全交给 Agent，Agent 接管浏览器、录制回放操作、顺手把数据发回来；甚至做了多智能体共享会话缓存，想省掉给每个平台定制的成本。听着很无感很先进。</p><p>但我自己掂量下来否了，原因很实在：</p><ul><li>上下文会混乱，多个人的活儿硬塞进共享上下文，有概率串味。</li><li>鸡蛋全在一个篮子，一处出问题整条线全塌。企业方案最忌讳这个。</li><li>贵，而且要保证不出错的代价不成比例。</li></ul><p>最后把方案收敛成：填报这件事根本不用 Agent，员工填一张表单，程序做字段映射、一键分发、入库回测，全是普通程序员基本功，安全、便宜、快。</p><p>这段经历就是这道题的答案本身：我不是不会上 Agent，是我试过把它上到不该上的地方，然后自己把它拿下来了。<strong>知道 Agent 的边界，比会用 Agent 更值钱。</strong></p><hr><h2 id="诚实边界" tabindex="-1">诚实边界 <a class="header-anchor" href="#诚实边界" aria-label="Permalink to &quot;诚实边界&quot;">​</a></h2><p>Agent 那几块（聚类、生成、归因）出的都是草稿，要人审——归因草稿可能编因果，素材候选可能踩合规。方案里这些地方全带人审边界，不是 AI 说了算。</p><p>&quot;规则能不能写出来&quot;这条线实操里有灰度，我不教条，一件一件看。那个共享缓存的想法我留着当自己的实验，但清楚它的定位，不往生产方案里塞。</p><hr><details class="details custom-block"><summary>📱 微信简版 — 可直接发送</summary><p>第六题——哪些真需要 Agent，哪些规则脚本就够。</p><p>判断标准一句话：这件事的逻辑能不能用规则写出来。能写的用脚本，确定、成本低、错了一眼能定位；写不出来、得靠理解人话和杂乱信息的，才上 Agent。</p><p>方案里绝大多数是脚本的活：字段对齐、去重入库、增删改查，要的是永远不出错。真需要 Agent 的是少数但值钱：聚类客服原话和竞品评论、生成素材候选、写归因草稿。注意异常报警是脚本，解释它为什么发生才是 Agent。</p><p>说个我自己的取舍：我一度想把填报全交给 Agent、还想搞多智能体共享缓存，后来自己否了——太重、风险集中，进不了生产，只当实验。知道 Agent 的边界、忍得住不乱上，比会用它更重要。</p></details>',33)])])}const q=e(n,[["render",l]]);export{h as __pageData,q as default};
